mapper.select:
SELECT id, title, status, close_at, total_pool, created_at FROM market WHERE deleted_at IS NULL
AND status = #{status}
AND title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM market WHERE deleted_at IS NULL
AND status = #{status}
AND title LIKE CONCAT('%', #{keyword}, '%')

SELECT id, market_id, option_code, option_text, display_order, range_min, range_max, min_inclusive, max_inclusive, virtual_pool_amount, real_pool_amount, total_contract_quantity, current_price, prediction_count, is_result, created_at, updated_at FROM market_option WHERE market_id IN
#{marketId}
ORDER BY market_id ASC, display_order ASC, id ASC

SELECT history.id AS history_id, history.market_id, history.option_id, market_option.option_text AS option_content, history.prediction_id, history.event_type, history.price_before, history.price_after, history.real_pool_before, history.real_pool_after, market_option.virtual_pool_amount, history.contract_quantity_before, history.contract_quantity_after, history.created_at FROM market_price_history history JOIN market_option ON market_option.id = history.option_id AND market_option.market_id = history.market_id
WHERE history.market_id = #{marketId}
AND history.option_id = #{optionId}
ORDER BY history.created_at ASC, history.id ASC LIMIT #{limit} OFFSET #{offset}

SELECT *
FROM market_reputation_update
WHERE prediction_id = #{predictionId}

mapper.update:
UPDATE market
SET status = 'ACTIVE',
    updated_at = #{updatedAt}
WHERE id = #{marketId}
  AND status = 'PENDING'
  AND close_at > #{updatedAt}
  AND initial_virtual_liquidity > 0
  AND deleted_at IS NULL

UPDATE market
SET status = 'VOIDED',
    updated_at = #{updatedAt}
WHERE id = #{marketId}
  AND status IN ('PENDING', 'ACTIVE', 'CLOSED', 'DATA_PENDING')
  AND deleted_at IS NULL

mapper.select:
SELECT COUNT(*)
FROM market_refund_detail
WHERE market_void_id = #{marketVoidId}

SELECT *
FROM market_refund_detail
WHERE market_void_id = #{marketVoidId}
  AND (
        status IN ('FAILED', 'UNKNOWN')
        OR (
            status = 'PENDING'
            AND updated_at <= #{pendingThreshold}
        )
  )
ORDER BY id ASC
FOR UPDATE

mapper.update:
UPDATE market_prediction
SET status = 'REFUND_PENDING',
    updated_at = #{updatedAt}
WHERE id = #{predictionId}
  AND status = 'CONFIRMED'

UPDATE market_refund_detail
SET status = #{status},
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{detailId}
  AND status = 'PENDING'

UPDATE market_refund_detail
SET status = #{status},
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{detailId}
  AND status IN ('FAILED', 'UNKNOWN', 'PENDING')

UPDATE market_prediction
SET status = 'REFUND_UNKNOWN',
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{predictionId}
  AND status = 'REFUND_PENDING'

UPDATE market_prediction
SET status = 'REFUND_PENDING',
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{predictionId}
  AND status IN ('REFUND_PENDING', 'REFUND_UNKNOWN')

UPDATE market_void
SET refund_status = #{refundStatus},
    updated_at = #{updatedAt}
WHERE id = #{marketVoidId}

UPDATE market_option
SET is_result = FALSE,
    updated_at = #{updatedAt}
WHERE market_id = #{marketId}

UPDATE market_option
SET is_result = TRUE,
    updated_at = #{updatedAt}
WHERE id = #{resultOptionId}
  AND market_id = #{marketId}

mapper.select:
SELECT *
FROM market_option
WHERE id = #{optionId}

SELECT *
FROM market_prediction
WHERE market_id = #{marketId}
  AND member_id = #{memberId}

SELECT *
FROM market_prediction
WHERE market_id = #{marketId}
  AND member_id = #{memberId}
FOR UPDATE

SELECT *
FROM market_prediction
WHERE id = #{predictionId}

SELECT *
FROM market_prediction
WHERE status = 'POINT_UNKNOWN'
   OR (
        status = 'POINT_PENDING'
        AND updated_at <= #{pendingThreshold}
   )
ORDER BY updated_at ASC, id ASC
LIMIT #{limit}

mapper.update:
UPDATE market
SET total_pool = total_pool + #{pointAmount},
    updated_at = #{updatedAt}
WHERE id = #{marketId}
  AND deleted_at IS NULL

UPDATE market_option
SET real_pool_amount = #{realPoolAmount},
    total_contract_quantity = #{totalContractQuantity},
    current_price = #{currentPrice},
    prediction_count = #{predictionCount},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND market_id = #{marketId}

UPDATE market_prediction
SET status = #{status},
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{predictionId}
  AND status = 'POINT_PENDING'

UPDATE market_prediction
SET status = 'FAILED',
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{predictionId}
  AND status IN ('POINT_PENDING', 'POINT_UNKNOWN')

UPDATE market_prediction
SET status = 'POINT_UNKNOWN',
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{predictionId}
  AND status = 'POINT_PENDING'

UPDATE market
SET status = 'SETTLEMENT_IN_PROGRESS',
    updated_at = #{updatedAt}
WHERE id = #{marketId}
  AND status = 'CLOSED'
  AND deleted_at IS NULL

mapper.select:
SELECT COUNT(*)
FROM market_settlement_detail
WHERE settlement_id = #{settlementId}

SELECT COUNT(*)
FROM market_prediction
WHERE market_id = #{marketId}
  AND option_id != #{resultOptionId}
  AND status = 'SETTLED'

mapper.update:
UPDATE market_settlement_detail
SET status = #{status},
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{detailId}
  AND status = 'PENDING'

UPDATE market_settlement_detail
SET status = #{status},
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{detailId}
  AND status IN ('FAILED', 'UNKNOWN')

UPDATE market_prediction
SET status = 'SETTLED',
    settled_amount = #{settledAmount},
    updated_at = #{updatedAt}
WHERE id = #{predictionId}
  AND status = 'CONFIRMED'

UPDATE market_prediction
SET status = 'SETTLED',
    settled_amount = 0.00,
    updated_at = #{updatedAt}
WHERE market_id = #{marketId}
  AND option_id != #{resultOptionId}
  AND status = 'CONFIRMED'

UPDATE market_prediction
SET status = 'SETTLED',
    settled_amount = 0.00,
    updated_at = #{updatedAt}
WHERE market_id = #{marketId}
  AND status = 'CONFIRMED'

UPDATE market_settlement
SET status = 'COMPLETED',
    settled_at = #{updatedAt},
    updated_at = #{updatedAt}
WHERE id = #{settlementId}
  AND status = 'IN_PROGRESS'

UPDATE market_settlement
SET updated_at = #{updatedAt}
WHERE id = #{settlementId}
  AND status = 'IN_PROGRESS'
